import json
import os
from typing import Any, Dict, Optional


class Config:
    def __init__(self, data: Dict[str, Any] = None, env_prefix: str = "APP"):
        self._data = data or {}
        self._env_prefix = env_prefix

    @classmethod
    def from_file(cls, path: str, env_prefix: str = "APP") -> "Config":
        with open(path) as f:
            return cls(json.load(f), env_prefix=env_prefix)

    def _env_key(self, key: str) -> str:
        """Convert dot-notation key to env var name."""
        return f"{self._env_prefix}_{key.replace('.', '_').upper()}"

    def get(self, key: str, default: Any = None) -> Any:
        """Get config value. Env vars override file values."""
        # Check environment variable first
        env_name = self._env_key(key)
        env_val = os.environ.get(env_name)
        if env_val is not None:
            return env_val
        # Fall back to file data
        parts = key.split('.')
        current = self._data
        for part in parts:
            if isinstance(current, dict) and part in current:
                current = current[part]
            else:
                return default
        return current
